// Java 25 exam prep - Stream pipelines run once
// Learn: intermediate ops stay lazy until one terminal op consumes the stream.
import java.util.List;
import java.util.stream.Stream;

List<String> names = List.of("Ada", "Linus", "Grace", "Alan");
Stream<String> pipeline = names.stream()
  .filter(name -> name.length() > 3)
  .map(String::toUpperCase);
// Nothing has executed yet: filter and map only describe the pipeline.
List<String> longNames = pipeline.toList();
System.out.println(longNames);
// A second terminal op such as pipeline.count() throws IllegalStateException.
